<div class="card border-0 shadow-sm"><div class="card-body p-4"><h2 class="h5">Feedbacks</h2><table class="table align-middle"><thead><tr><th>Cliente</th><th>Nota</th><th>Mensagem</th><th>Publicado</th><th></th></tr></thead><tbody><?php foreach ($feedbacks as $feedback): ?><tr><td><?= e($feedback['client_name']) ?></td><td><?= e((string) $feedback['rating']) ?></td><td><?= e($feedback['message']) ?></td><td><?= $feedback['is_published'] ? 'Sim' : 'Não' ?></td><td><form method="post" action="/admin/feedbacks/<?= e((string) $feedback['id']) ?>/toggle-publicacao"><?= \App\Core\Csrf::field() ?><button class="btn btn-outline-dark btn-sm">Alternar</button></form></td></tr><?php endforeach; ?></tbody></table></div></div>
